function printMessage(message) {
    let chatData = { content: message };
    ChatMessage.applyRollMode(chatData, game.settings.get("core", "rollMode"));
    ChatMessage.create(chatData, {})
};

function resetRollTables(item, index) {
    game.tables.getName(item).resetResults();;
}

try {
    let rollTableName = "Third Call - Voices in the Void";
    let rollTableTitle = "Third Call - Voices in the Void";
    let title = "<h2>" + rollTableTitle + "</h2>";
    let message = "On a Caller’s third call, generate a follow-up to the previous call – a twist or turn in their story.";

    printMessage(title + message);
    const songBlockRoll = await game.tables.getName(rollTableName).draw(options = { recursive: true, rollMode: game.settings.get("core", "rollMode") });
}
catch (e) {
    console.log(e);
}
